17	const COMPONENT_BASE_PREMIUM = 25;
18	
19	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: COMPONENT_BASE_PREMIUM,
25	  moonstone: COMPONENT_BASE_PREMIUM,
26	};
27	
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const PROCESSING_FEE = 5;
30	
31	const CURSED_SURCHARGE_RATE = 0.5;
32	
33	function riskMultiplierForItem(item: Item): number {
34	  return 1 + (item.cursed ? CURSED_SURCHARGE_RATE : 0);
35	}
36	
37	function basePremiumForItem(item: Item): number {
38	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
39	}
40	
41	type QuoteResult = { kind: "quote"; premium: number };
42	
43	const BUILDING_BLOCK_BASE_PREMIUM = 60;
44	const BUILDING_BLOCK_SIZE = 3;
45	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
46	
47	type ItemGroup = { kind: Item["kind"]; items: Item[] };
48	
49	function groupByKind(items: Item[]): ItemGroup[] {
50	  const groups = new Map<Item["kind"], Item[]>();
51	  for (const item of items) {
52	    const group = groups.get(item.kind) ?? [];
53	    group.push(item);
54	    groups.set(item.kind, group);
55	  }
56	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
57	}
58	
59	function isBuildingBlock(group: ItemGroup): boolean {
60	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
61	}
62	
63	function basePremiumForGroup(group: ItemGroup): number {
64	  if (isBuildingBlock(group)) {
65	    return BUILDING_BLOCK_BASE_PREMIUM;
66	  }
67	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
68	}
69	
70	function basePremiumForItems(items: Item[]): number {
71	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
72	}
73	
74	function quoteStep(step: QuoteStep): QuoteResult {
75	  const basePremium = basePremiumForItems(step.items);
76	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
77	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
78	  return { kind: "quote", premium };
79	}
80	
81	export function processScenario(scenario: Scenario): ScenarioResult {
82	  const results = scenario.steps.map(quoteStep);
83	  return { results };
84	}
